var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mmm...","TWN":"唔……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"으윽! 머리야…… 아까 폭발 때문에…… 기절한 건가?","JPN":"ううっ！　頭痛い……さっきの爆発で……気絶してたのか？","ENG":"Urgh! My head... Did I faint because of the explosion...?","TWN":"呃！我的頭……我是因為剛剛的爆炸……才暈過去的嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"엇!? 우리 부스가…… 완전히 무너졌잖아!?","JPN":"えっ！？　僕たちのブースが……完全に崩れてる！？","ENG":"Huh?! Our booth... It’s completely destroyed!","TWN":"唔！？我們的攤位……根本變成廢墟啦！？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"다들 그렇게 열심히 준비했는데…….","JPN":"みんなであんなに一生懸命準備したのに……","ENG":"After all the work we put in...","TWN":"我們準備得那麼辛苦……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"잠깐, 누나들은 어디간거지……? 갑자기 행사장은 왜 폭발한 거고……?","JPN":"待てよ、みんなはどこ行ったんだろう……？　会場はなんで突然爆発したんだ……？","ENG":"Wait, where are the girls...? Why did the convention center explode, all of a sudden...?","TWN":"等一下，姊姊她們呢……？展場為什麼會突然爆炸……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"음……?","JPN":"うん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"아, 아아아앗!? 자, 잠깐만! 어, 어디갔지!?","JPN":"あ、ああああっ！？　あ、あれ？　ど、どこにいったんだろう！？","ENG":"A-Ahhhhh?! W-wait! W-where did it go?!","TWN":"啊啊啊啊啊！？怎…怎麼不見了！跑…跑哪去了！？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"내 마스크……! 내 샐러리맨X 마스크……!","JPN":"僕のマスク……！　僕のサラリーマンXのマスク……！","ENG":"My mask...! My Salaryman X mask...!","TWN":"我的面具……！我的上班族X面具呢……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……이쪽은 대충 정리됐나?","JPN":"……こっちはだいたい片付いたか？","ENG":"...All clear over here.","TWN":"……這裡處理得差不多了唄？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"타이밍도 윽수로 나쁘네. 하필 코미페 날에 사고가 터지는 건 뭔데?","JPN":"タイミング悪すぎやで。コミフェの日に事故なんてな。","ENG":"Such bad timing. Why did it have to be the day of Comic Festival, out of all days?","TWN":"還真會挑時間，偏偏挑在動漫展的時候出事？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"리네야! 사람들도 대부분 대피했어. 선생님도 곧 지원을 보내신데!","JPN":"マリちゃん！　みんなほとんど避難したよ。先生ももうすぐ応援を送ってくれるって！","ENG":"Rinae! We’re almost done with the evacuation. Teach is sending us support!","TWN":"璃奈！人差不多都離開了，老師也說會派支援過來！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"좋네, 이제 쌤이 보낸 지원이 올 때까지 마무리만 하고 있음 되나?","JPN":"良かったわ、ここからは先生が送った応援が来るまでに終わらせればええか？","ENG":"Good, so all we gotta do is to stay low until help comes?","TWN":"太好了，那就整理一下，等老師的支援抵達唄？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……아직이야.","JPN":"……まだ。","ENG":"...Not so fast.","TWN":"……還沒結束。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"부상하고 있어…… 뭔가가!","JPN":"浮上してる……何かが！","ENG":"It’s coming... something bad!","TWN":"有東西……接近中！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"에엥!? 뭐가 또 온다고!?","JPN":"ええっ！？　また何かが来るやて！？","ENG":"Eh?! There’s more of ‘em?","TWN":"啥！？又有啥東東接近中！？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하아…… 끝도 없네, 끝도 없어.","JPN":"はあ……キリないやん、キリない。","ENG":"*Sigh...* There is no end, indeed.","TWN":"哀……一波未平一波又起。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"3…… 2…… 1…… 온다.","JPN":"3……2……1……来る。","ENG":"3, 2, 1... Here it comes.","TWN":"3……2……1……來了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"준비해…… 2종이야!","JPN":"準備して……第2種！","ENG":"Be prepared... It's a Category 2!","TWN":"準備……是2類！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"뭔가…… 그 느낌 같아…… 그때 그 공장에서…….","JPN":"何か……あの感じだ……あの時、あの工場での……","ENG":"It feels like... back then... at the factory...","TWN":"好熟悉……的感覺……跟那時候在工廠一樣……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"머리가…… 어지럽고…… 금방이라도 토할 것 같아…….","JPN":"頭が……グラグラして……今すぐにでも吐きそう……","ENG":"I feel sick... and dizzy... Like I’m about to throw up...","TWN":"頭……好暈……好想吐……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"하지만 누나들을 찾아야 해. 누나들은 어딨는 거야……?","JPN":"でもみんなを探さないと。どこにいるんだ……？","ENG":"But I need to find the girls. Where could they be...?","TWN":"可是我要找到姊姊們，她們到底在哪……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"음? 저건……?","JPN":"うん？　あれは……？","ENG":"Mm? That’s...","TWN":"嗯？那是……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"괴, 괴물……?","JPN":"ば、化け物……？","ENG":"A-a monster?","TWN":"怪…怪物……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"공장에서 봤던 거랑은 차원이 달라……!","JPN":"工場で見たのとは格が違う……！","ENG":"It’s nothing like the ones I saw at the factory...!","TWN":"和那時候在工廠看到的威力完全不一樣……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"빠, 빨리…… 도망쳐야 해……!","JPN":"は、早く……逃げないと……！","ENG":"Q-quick... I have to run away...!","TWN":"快，快……快逃……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"앗!","JPN":"あっ！","ENG":"Ah!","TWN":"啊！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"이, 이젠 끝이야……! 아, 아직 죽고 싶지 않은데……!","JPN":"も、もう終わりだ……！　ま、まだ死にたくないのに……！","ENG":"I-I’m done for...! B-but I don’t want to die yet...!","TWN":"完…完蛋了……！我…我還不想死啊……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마, 박스 니 괘안나?","JPN":"ちょっと、ダンボール、あんた大丈夫か？","ENG":"Box! Ya good?","TWN":"喂，紙箱，你沒事唄？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"내 왔으니까, 이제 걱정하지 마라.","JPN":"ウチが来たやから、もう心配あらへん。","ENG":"Mi Rinae is here to save ya butt. You’re safe.","TWN":"別怕，我來了。"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"미, 미리네 누나……?","JPN":"ま、マリさん……？","ENG":"R-Rinae...?","TWN":"宓…宓璃奈姊姊……？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 저 아이가…… 박스 군이라고?","JPN":"え？　あの子が……ダンボール君なの？","ENG":"Huh? That little boy... is Boxie?","TWN":"嗯？他就是……紙箱小朋友？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬? 니 박스 얼굴 처음 보나?","JPN":"何言うてんねん？　タエ、ダンボールの顔見たことないんか？","ENG":"What? You ain’t seen his face before?","TWN":"幹啥？你第一次看到紙箱的臉嗎？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? 리네는 박스 군 얼굴 본 적 있었어?","JPN":"え？　マリちゃんはダンボール君の顔見たことあったの？","ENG":"Oh? Have you, Rinae?","TWN":"嗯？璃奈，你看過紙箱小朋友的臉嗎？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 맞네! 아, 아하하…….","JPN":"あ、せやった！　あ、あはは……","ENG":"Ah, right! A-ah ha ha...","TWN":"對吼！哈，哈哈……"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그기 그러니까…… 아, 몰라! 암튼 그런 게 있다!","JPN":"それが、やから……ああ、もうええ！　とにかく見たことあるねん！","ENG":"I mean... gah, whatever! It’s a long story!","TWN":"那個……不知道啦！總之就是這樣！"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"집중해…… 미리네. 2종이야.","JPN":"集中して……マリ。第2種。","ENG":"Focus, Rinae... They’re Category 2.","TWN":"專心……宓璃奈，是2類。"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"힘겨울 거야…… 아마도.","JPN":"手ごわい……たぶん。","ENG":"It won’t be easy... probably.","TWN":"不好對付……可能。"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"버텨야 해…… 지원이 올 때까지.","JPN":"持ちこたえないと……応援が来るまで。","ENG":"We need to hold on... until reinforcement comes.","TWN":"撐住……在支援抵達前。"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"누, 누나들…… 지금 저 괴물이랑 싸우겠다고요?","JPN":"マリさんたち……今、あの化け物と戦うつもりなんですか？","ENG":"Y-you’re joking... You’re not thinking of fighting that monster, are you?","TWN":"姊…姊姊，你們……現在是要對付那個怪物嗎？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"아, 안 돼요! 누나들 다칠지도 모른다고요! 전 누나들 다치는 거 싫어요!","JPN":"だ、ダメですよ！　みんな、怪我をするかもしれません！　僕はみんながケガするのイヤです！","ENG":"No way! You might get hurt! I don’t want anybody to get hurt!","TWN":"不…不可以！你們很可能會受傷！我不要你們受傷！"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"그래, 저랑 같이 도망가요! 누나들도 싸우기 싫잖아요!","JPN":"そうだ、僕と一緒に逃げましょうよ！　マリさんたちも戦いたくないでしょう？","ENG":"Yeah, you could run away with me instead! It’s not like you want to fight, do you?","TWN":"和我一起逃吧！你們也不想打吧？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쯧쯔. 그라믄 안 돼, 그라믄.","JPN":"ちっちっ。そんなんあかん、そんなん。","ENG":"Tsk tsk... That ain’t right.","TWN":"嘖嘖，不可以這樣唄！"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"네?","JPN":"え？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우린 카운터다 안 카나. 우리가 안 하면 누가 저걸 막는데?","JPN":"ウチらはカウンターや。ウチらがやらへんと、誰もあれを止められへん。","ENG":"We are Counters. If we don’t stop them, who will?","TWN":"我們是制裁者，我們不打的話，誰要來阻止那個怪物？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"미리네. 그건…….","JPN":"マリ。それは……","ENG":"Rinae. That's...","TWN":"宓璃奈，那個……"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마, 됐다. 상황이 이 꼬라진데, 박스 야도 알 건 알아야지 않겠나?","JPN":"ま、ええって。こんな状況やし、ダンボールもこれくらいは知っておかんと。","ENG":"It’s fine. Look at what’s going on around here. Kiddo’s gotta know what we’re dealing with.","TWN":"沒關係啦！事已至此，有些事也應該要讓紙箱知道唄？"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이깟 침식체 별것도 아이다. 그니까 여는 우리들한테 맡기고 얼른 튀라.","JPN":"この程度の侵食体、どうってことあらへん。だからここはウチらに任せて、はよ逃げて。","ENG":"These C.O.s mean nothin’ to me. So go, leave it to us.","TWN":"這種侵蝕體不算什麼，交給我們處理就好，你趕快逃唄！"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 내는 자신 있다 안 하나?","JPN":"へへっ、ウチは自信あるんやから。","ENG":"Heh. As I always say... Ain’t nothin’ stoppin’ me!","TWN":"嘿嘿，我有信心！"},"stage":{"bg":"GAMECIRCLE_06","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그래, 박스 군…… 여긴 우리한테 맡겨……!","JPN":"そうだよ、ダンボール君……ここは私たちに任せて……！","ENG":"Yes, Boxie...! Leave it to us...!","TWN":"沒錯，紙箱小朋友……這裡就交給我們……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응, 부끄러운 게 아니야…… 도망치는 건.","JPN":"うん、恥じゃない……逃げるのは。","ENG":"Isn’t something to be ashamed of... running away...","TWN":"嗯，逃跑……不可恥。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"그, 그렇지만…….","JPN":"で、でも……","ENG":"B-but...","TWN":"可…可是……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마, 시간 없다! 디지기 싫으면 빨랑 튀라고!","JPN":"もう、時間がない！　死にたくなかったらはよ逃げて！","ENG":"Kiddo, we ain’t got no time! Run, if you wanna live!","TWN":"喂，沒時間了！不想死的話就快逃！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"으아아아아아아아아아아……!","JPN":"うわあああああああああ……！","ENG":"Uaaahhh...!","TWN":"啊啊啊啊啊啊啊啊……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_GAMECIRCLE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"하아…… 하아…….","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"지금까지 난 도망만 쳤는데…… 결국, 또 도망치고 말았어……","JPN":"今までも僕は逃げてばっかりだったけど……結局、また逃げちゃった……","ENG":"All my life I’ve been running away from things... Yet here I am again.","TWN":"我的人生，到目前為止一直在逃……只是不斷地逃……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"나는…… 대체……","JPN":"僕は……いったい……","ENG":"Why am I... so...","TWN":"我……到底……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"음, 이건……!?","JPN":"うん、これは……？","ENG":"Mm? This must be...?!","TWN":"嗯？這是……！？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};